	private Explanation explain(Explanation.Level level, String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			return conn.prepareTupleQuery(query).explain(level);
		}
	}

	private static String rowQuery() {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?price WHERE { ?s a ex:Item ; ex:price ?price }";
	}

	private static String aggregateQuery() {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(*) AS ?count) WHERE { ?s a ex:Item ; ex:price ?price }";
	}

	private static void assertNativeMarker(Explanation explanation, String expectedKind, String description) {
		assertThat(hasPlannedMetric(explanation.toGenericPlanNode(), PLANNED_EXECUTION_ENGINE, LMDB_NATIVE))
				.as(description + " generic plan node should expose the LMDB native marker")
				.isTrue();
		assertThat(hasPlannedMetric(explanation.toGenericPlanNode(), PLANNED_EXECUTION_KIND, expectedKind))
				.as(description + " generic plan node should expose the LMDB native execution kind")
				.isTrue();

		assertThat(explanation.toString()).contains(PLANNED_EXECUTION_ENGINE + "=" + LMDB_NATIVE);
		assertThat(explanation.toString()).contains(PLANNED_EXECUTION_KIND + "=" + expectedKind);
		assertThat(explanation.toJson()).contains("\"" + PLANNED_EXECUTION_ENGINE + "\"");
		assertThat(explanation.toJson()).contains("\"" + PLANNED_EXECUTION_KIND + "\"");
		assertThat(explanation.toDot()).contains(LMDB_NATIVE);
		assertThat(explanation.toDot()).contains(expectedKind);
	}

	private static void assertNoNativeMarker(Explanation explanation) {
		assertThat(explanation.toString()).doesNotContain(PLANNED_EXECUTION_ENGINE);
		assertThat(explanation.toJson()).doesNotContain(PLANNED_EXECUTION_ENGINE);
		assertThat(explanation.toDot()).doesNotContain(LMDB_NATIVE);
		assertThat(hasPlannedMetric(explanation.toGenericPlanNode(), PLANNED_EXECUTION_ENGINE, LMDB_NATIVE))
				.isFalse();
	}

	private static boolean hasPlannedMetric(GenericPlanNode node, String metricName, String metricValue) {
		if (node == null) {
			return false;
		}
		if (Objects.equals(metricValue, node.getStringMetricPlanned(metricName))) {
			return true;
		}
		if (node.getPlans() == null) {
			return false;
		}
		return node.getPlans()
				.stream()
				.anyMatch(child -> hasPlannedMetric(child, metricName, metricValue));
	}

	private static boolean hasPlannedMetricOnType(GenericPlanNode node, String type, String metricName,
			String metricValue) {
		if (node == null) {
			return false;
		}
		if (Objects.equals(type, node.getType())
				&& Objects.equals(metricValue, node.getStringMetricPlanned(metricName))) {
			return true;
		}
		if (node.getPlans() == null) {
			return false;
		}
		return node.getPlans()
				.stream()
				.anyMatch(child -> hasPlannedMetricOnType(child, type, metricName, metricValue));
	}

	private static boolean hasActualMetricOnType(GenericPlanNode node, String type, String metricName) {
		if (node == null) {
			return false;
		}
		if (Objects.equals(type, node.getType()) && node.getStringMetricActual(metricName) != null) {
			return true;
		}
		if (node.getPlans() == null) {
			return false;
		}
		return node.getPlans()
				.stream()
				.anyMatch(child -> hasActualMetricOnType(child, type, metricName));
	}

	private static void restoreProperty(String previous) {
		restoreProperty(previous, NATIVE_FLAG);
	}

	private static void restoreProperty(String previous, String property) {
		if (previous == null) {
			System.clearProperty(property);
		} else {
			System.setProperty(property, previous);
		}
	}
